INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '50740dbe-0896-4926-b4d4-6fb026855247',
  '00000000-0000-0000-0000-000000000001',
  $escape$axum — REST Versioning and OpenAPI Generation Without the Boilerplate$escape$,
  $escape$axum's `Router::nest()` makes URL-based API versioning trivial — nest versioned routers under `/v1`, `/v2` prefixes and share state across all of them via `Router::with_state()`. Each version gets its own handler set without duplicating middleware. For OpenAPI generation, pair axum with `utoipa`: annotate handlers with `#[utoipa::path]`, aggregate them in an `OpenApi` derive macro, and mount the spec via `utoipa_swagger_ui::SwaggerUi`. This avoids manual spec maintenance entirely. One sharp edge: `nest()` strips the prefix before matching, so nested routers must not re-declare the prefix. For header-based versioning (`Accept: application/vnd.api+json;version=2`), implement a custom `FromRequestParts` extractor that parses the header and returns a typed `ApiVersion` enum — axum's extractor system makes this a first-class citizen, not middleware hacks. Prefer URL versioning for public APIs (CDN-cacheable, easy to test with curl) and header versioning for internal service-to-service contracts where you control both ends.$escape$,
  $escape$use axum::{Router, routing::get};

async fn v1_users() -> &'static str { "[v1] users" }
async fn v2_users() -> &'static str { "[v2] users" }

pub fn build_router() -> Router {
    let v1 = Router::new().route("/users", get(v1_users));
    let v2 = Router::new().route("/users", get(v2_users));

    Router::new()
        .nest("/v1", v1)
        .nest("/v2", v2)
}$escape$,
  $escape$rust$escape$,
