INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd0d31834-b891-407e-9b8f-55a04db47ecf',
  '00000000-0000-0000-0000-000000000001',
  $escape$axum Configuration — Typed Settings, Env Vars, and Secrets Without the Boilerplate$escape$,
  $escape$axum has no built-in config system, so the idiomatic pattern is a typed `AppConfig` struct deserialized at startup and injected via `State`. Reach for `envy` to deserialize environment variables directly into a struct that derives `serde::Deserialize` — no manual `std::env::var` chains. Pair it with `dotenvy::dotenv()` at the top of `main` to load `.env` in development without leaking it to production. For secrets (DB passwords, API keys), wrap sensitive fields in `secrecy::Secret<String>` — this prevents the value from appearing in `Debug` output or logs. Pass the config into your axum router via `Router::with_state(Arc::new(config))`, then extract it in handlers with `State(config): State<Arc<AppConfig>>`. Avoid storing raw secrets in `AppConfig` fields you'd ever `#[derive(Debug)]` on without `secrecy`. For multi-environment layering (base + override files), swap `envy` for the `config` crate, which supports TOML/YAML/env merging in priority order.$escape$,
  $escape$use axum::{extract::State, routing::get, Router};
use secrecy::Secret;
use std::sync::Arc;

#[derive(serde::Deserialize)]
pub struct AppConfig {
    pub database_url: Secret<String>,
    pub port: u16,
    pub jwt_secret: Secret<String>,
}

#[tokio::main]
async fn main() {
    dotenvy::dotenv().ok();
    let config: AppConfig = envy::from_env().expect("invalid config");
    let app = Router::new()
        .route("/", get(handler))
        .with_state(Arc::new(config));
    let listener = tokio::net::TcpListener::bind("0.0.0.0:3000").await.unwrap();
    axum::serve(listener, app).await.unwrap();
}

async fn handler(State(cfg): State<Arc<AppConfig>>) -> String {
    format!("Listening on port {}", cfg.port)
}$escape$,
  $escape$rust$escape$,
