INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3b0f665a-23a2-40db-9092-c6f49dbcfb73',
  '00000000-0000-0000-0000-000000000001',
  $escape$axum Request Logging — Structured Traces and Correlation IDs$escape$,
  $escape$axum delegates request logging to `tower-http`'s `TraceLayer`, which hooks into the `tracing` ecosystem. Add it via `ServiceBuilder` and you get per-request spans automatically. For structured logs, configure `tracing-subscriber` with `fmt::layer().json()` — every `tracing::info!` call within a request span will carry its span fields (method, uri, status, latency) in the emitted JSON.

Correlation IDs require a custom `tower::Layer`. Extract `x-request-id` from incoming headers (or generate a UUID if absent), store it in a `tracing::Span` field via `span.record("request_id", &id)`, and propagate it downstream. Inject the same ID into the response header inside the layer's `call` implementation.

Use `TraceLayer::new_for_http().make_span_with(...)` to customise the root span — add `request_id`, `user_id`, or tenant fields at span creation time so every log line inside that request automatically carries them. Avoid `println!`; use `tracing::info!(status = %resp.status(), "response sent")` so fields stay machine-parseable in production.$escape$,
  $escape$use tower_http::trace::{TraceLayer, DefaultMakeSpan};
use tracing_subscriber::{layer::SubscriberExt, util::SubscriberInitExt, fmt};
use uuid::Uuid;

// In main:
tracing_subscriber::registry()
    .with(fmt::layer().json())
    .init();

let app = Router::new()
    .route("/", get(handler))
    .layer(
        TraceLayer::new_for_http()
            .make_span_with(|req: &Request<_>| {
                let id = req.headers()
                    .get("x-request-id")
                    .and_then(|v| v.to_str().ok())
                    .map(String::from)
                    .unwrap_or_else(|| Uuid::new_v4().to_string());
                tracing::info_span!("request", request_id = %id, method = %req.method(), uri = %req.uri())
            }),
    );$escape$,
  $escape$rust$escape$,
