INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '555b7974-a1c0-4105-93f3-d8389c0afa8e',
  '00000000-0000-0000-0000-000000000001',
  $escape$axum Observability — Health Checks, Prometheus Metrics, and Distributed Tracing$escape$,
  $escape$axum pairs naturally with Tower's middleware ecosystem to wire up production observability in minutes. For health checks, expose a `/health` route returning 200 JSON — liveness and readiness variants let Kubernetes differentiate between "restart me" and "stop sending traffic". For metrics, `axum-prometheus` wraps the `metrics` crate and auto-instruments every route with request count, latency histograms, and in-flight gauges via a `PrometheusMetricLayer` inserted into your `Router`. Scrape `/metrics` with Prometheus and you get per-route `axum_http_requests_total` labels out of the box. For distributed tracing, `tower-http`'s `TraceLayer` generates spans for every request. Pair it with `tracing-opentelemetry` and an OTLP exporter to propagate `traceparent` headers across services. The critical detail: insert `TraceLayer` before `PrometheusMetricLayer` in the layer stack so trace context is available when metrics middleware runs. All three concerns compose without touching handler code — pure Tower layer separation.$escape$,
  $escape$use axum::{routing::get, Router, Json};
use axum_prometheus::PrometheusMetricLayer;
use tower_http::trace::TraceLayer;
use serde_json::json;

async fn health() -> Json<serde_json::Value> {
    Json(json!({ "status": "ok" }))
}

#[tokio::main]
async fn main() {
    let (prometheus_layer, metrics_handle) = PrometheusMetricLayer::pair();

    let app = Router::new()
        .route("/health", get(health))
        .route("/metrics", get(|| async move { metrics_handle.render() }))
        .layer(TraceLayer::new_for_http())
        .layer(prometheus_layer);

    axum::serve(tokio::net::TcpListener::bind("0.0.0.0:3000").await.unwrap(), app)
        .await.unwrap();
}$escape$,
  $escape$rust$escape$,
